import React, { useState, useEffect } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshMovements, selectedMovement, setSelectedMovement }) => {
    const [product, setProduct] = useState({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });
    const [isEditing, setIsEditing] = useState(false);
    const [currentMovementId, setCurrentMovementId] = useState(null);

    useEffect(() => {
        if (selectedMovement) {
            setProduct(selectedMovement);
            setIsEditing(true);
            setCurrentMovementId(selectedMovement.id);
        } else {
            clearForm();
        }
    }, [selectedMovement]);

    const clearForm = () => {
        setProduct({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });
        setSelectedMovement(null); // Aqui está a chamada para limpar a movimentação selecionada
        setIsEditing(false);
        setCurrentMovementId(null);
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setProduct({ ...product, [name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!product.produto || !product.tipo_movimentacao || !product.quantidade) {
            alert("Por favor, preencha todos os campos obrigatórios.");
            return;
        }

        const dataToSend = {
            produto: product.produto,
            tipo_movimentacao: product.tipo_movimentacao,
            quantidade: parseInt(product.quantidade, 10),
            motivo: product.motivo || '',
        };

        console.log("Dados enviados:", JSON.stringify(dataToSend));

        try {
            if (isEditing) {
                await axios.put(`http://127.0.0.1:8000/api/movimentacoes/${currentMovementId}/`, dataToSend);
            } else {
                await axios.post('http://127.0.0.1:8000/api/movimentacoes/', dataToSend);
            }

            await refreshMovements();
            clearForm();
        } catch (error) {
            console.error("Erro ao registrar movimentação:", error.response ? error.response.data : error);
            alert("Erro: " + (error.response ? error.response.data.error : "Erro desconhecido."));
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <select name="produto" value={product.produto} onChange={handleChange} required>
                <option value="">Selecione um produto</option>
                {/* Mapeie seus produtos aqui */}
            </select>
            <select name="tipo_movimentacao" value={product.tipo_movimentacao} onChange={handleChange} required>
                <option value="entrada">Entrada</option>
                <option value="saida">Saída</option>
            </select>
            <input type="number" name="quantidade" value={product.quantidade} onChange={handleChange} placeholder="Quantidade" required />
            <input type="text" name="motivo" value={product.motivo} onChange={handleChange} placeholder="Motivo (opcional)" />

            <button type="submit">{isEditing ? "Atualizar" : "Adicionar"}</button>
            {isEditing && <button type="button" onClick={clearForm}>Cancelar</button>}
        </form>
    );
};

export default StockMovementForm;
